(()=>{'use strict';
const T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0,F=n=>N(n).toLocaleString('th-TH');
const sorter=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});let rows=[],meta={},payloadRef=null;
function $(s){return document.querySelector(s)}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function realTele(r){const tele=T(r.tele),ps=T(r.ps);if(!tele)return false;const kt=norm(tele),kp=norm(ps);if(kt&&kp&&(kt===kp||kp.includes(kt)||kt.includes(kp)))return false;return !!(r.isTele||tele)}
function appKey(){return meta.id||payloadRef?.version_id||meta.file_name||''}
function stateKey(){return 'doit-json:'+appKey()}
function historyKey(){return 'doit-print-history-v1:'+appKey()}
function filters(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value)}}
function pkFromData(x){return [x.brand||'',x.size||'',x.code||'',x.name||x.sku||'',x.type||''].join('|')}
function pk(r){return [r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
function state(){try{return JSON.parse(localStorage.getItem(stateKey())||'{}')}catch{return{}}}
function history(){try{return JSON.parse(localStorage.getItem(historyKey())||'[]')}catch{return[]}}
function scopeHead(){const f=filters();return[f.start,f.end,f.ps].join('|')+'|'}
function pkFromKey(k){return String(k).split('|').slice(4).join('|')}
function scopeRows(){const f=filters();return rows.filter(r=>!realTele(r)&&(!f.start||r.date>=f.start)&&(!f.end||r.date<=f.end)&&(!f.ps||r.ps===f.ps))}
function add(map,k,n){map.set(k,(map.get(k)||0)+N(n))}
function labelMap(){const m=new Map();scopeRows().forEach(r=>{const k=pk(r);if(!m.has(k))m.set(k,{key:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type})});history().forEach(h=>{const f=filters();if(h.start!==f.start||h.end!==f.end||h.ps!==f.ps)return;(h.items||[]).forEach(x=>{const k=pkFromData(x);if(!m.has(k))m.set(k,{key:k,brand:x.brand||'',size:x.size||'',code:x.code||'',sku:x.name||'',type:x.type||'',manual:!!x.manual})})});return m}
function build(){const order=new Map(),closed=new Map(),pending=new Map(),manual=new Map(),labels=labelMap();scopeRows().forEach(r=>add(order,pk(r),r.qty));history().forEach(h=>{const f=filters();if(h.start!==f.start||h.end!==f.end||h.ps!==f.ps)return;(h.items||[]).forEach(x=>{const k=pkFromData(x);add(closed,k,x.qty);if(x.manual)add(manual,k,x.qty)})});const st=state(),send=st.send||{};Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(k=>add(pending,pkFromKey(k),send[k]));const keys=new Set([...order.keys(),...closed.keys(),...pending.keys(),...manual.keys()]);return [...keys].map(k=>{const l=labels.get(k)||{key:k,brand:'',size:'',code:'',sku:k,type:''},o=N(order.get(k)),c=N(closed.get(k)),p=N(pending.get(k)),m=N(manual.get(k));return{...l,order:o,closed:c,pending:p,manual:m,remain:Math.max(o-c,0),over:Math.max(c-o,0)}}).sort((a,b)=>sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code||'',b.code||'')||sorter.compare(a.sku,b.sku))}
function csv(rows){const out=[['ชื่อรายการ','ออเดอร์_DOIT','ปิดบิลแล้ว','ค้างยังไม่ปิด','เหลือ/ขาด','ส่งเกิน','เพิ่มเอง']];rows.forEach(r=>out.push([r.sku,r.order,r.closed,r.pending,r.remain,r.over,r.manual]));const blob='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([blob],{type:'text/csv;charset=utf-8'}));a.download='doit-remaining-shortage-summary.csv';a.click()}
function css(){if($('#remainSummaryCss276'))return;const st=document.createElement('style');st.id='remainSummaryCss276';st.textContent='#remainOverlay{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:9998;display:flex;align-items:flex-end}#remainPanel{background:#fff;width:100%;max-height:88vh;border-radius:18px 18px 0 0;overflow:auto;color:#111827}#remainHead{position:sticky;top:0;background:#087b34;color:#fff;padding:10px 12px;display:flex;justify-content:space-between;gap:8px;align-items:center}#remainHead button{height:34px;border:1px solid #fff;background:#fff;color:#087b34;border-radius:8px;font-weight:900;padding:0 10px}.remainCards{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;padding:10px}.remainCards div{border:1px solid #e5e7eb;border-radius:10px;padding:8px;background:#f8fafc}.remainCards b{display:block;font-size:12px;color:#374151}.remainCards strong{font-size:18px}.remainNote{padding:0 10px 8px;color:#4b5563;font-size:12px}.remainWrap{overflow:auto;padding:0 10px 12px}.remainTbl{width:100%;border-collapse:collapse;min-width:920px;font-size:12px}.remainTbl th,.remainTbl td{border:1px solid #e5e7eb;padding:6px;text-align:center}.remainTbl th{background:#f8fafc}.remainTbl td:nth-child(4),.remainTbl th:nth-child(4){text-align:left}.bad{color:#dc2626;font-weight:900}.good{color:#15803d;font-weight:900}@media(max-width:640px){.remainCards{grid-template-columns:1fr 1fr}}';document.head.appendChild(st)}
function openSummary(){css();$('#remainOverlay')?.remove();const data=build();const totalOrder=data.reduce((s,r)=>s+r.order,0),totalClosed=data.reduce((s,r)=>s+r.closed,0),totalPending=data.reduce((s,r)=>s+r.pending,0),totalRemain=data.reduce((s,r)=>s+r.remain,0),totalOver=data.reduce((s,r)=>s+r.over,0),totalManual=data.reduce((s,r)=>s+r.manual,0);const f=filters();const ov=document.createElement('div');ov.id='remainOverlay';ov.innerHTML=`<section id="remainPanel"><div id="remainHead"><div><b>สรุปของเหลือ / ของขาด</b><br><small>วันที่ ${esc(f.start)} - ${esc(f.end)} · PS ${esc(f.ps||'ทั้งหมด')} · ไม่รวม Telesale</small></div><span><button id="remainCsv">Export</button> <button id="remainClose">ปิด</button></span></div><div class="remainCards"><div><b>ออเดอร์ DOIT</b><strong>${F(totalOrder)}</strong></div><div><b>ปิดบิลแล้ว</b><strong>${F(totalClosed)}</strong></div><div><b>ค้างยังไม่ปิด</b><strong>${F(totalPending)}</strong></div><div><b>เหลือ/ขาด</b><strong>${F(totalRemain)}</strong></div><div><b>ส่งเกิน/เพิ่มเอง</b><strong>${F(totalOver+totalManual)}</strong></div></div><div class="remainNote">เหลือ/ขาด = จำนวน DOIT ที่ยังไม่ถูกปิดบิลใน History. ค้างยังไม่ปิด = จำนวนที่ใส่ไว้ในหน้าปัจจุบันแต่ยังไม่ได้กดปิดบิล.</div><div class="remainWrap"><table class="remainTbl"><thead><tr><th>#</th><th>แบรนด์</th><th>ไซซ์</th><th>สินค้า</th><th>ออเดอร์</th><th>ปิดบิลแล้ว</th><th>ค้างยังไม่ปิด</th><th>เหลือ/ขาด</th><th>ส่งเกิน</th><th>เพิ่มเอง</th></tr></thead><tbody>${data.map((r,i)=>`<tr><td>${i+1}</td><td>${esc(r.brand)}</td><td>${esc(r.size)}</td><td>${esc(r.sku)}<br><small>${esc(r.code||'')}</small></td><td>${F(r.order)}</td><td>${F(r.closed)}</td><td>${F(r.pending)}</td><td class="${r.remain?'bad':'good'}">${F(r.remain)}</td><td>${F(r.over)}</td><td>${F(r.manual)}</td></tr>`).join('')||'<tr><td colspan="10">ไม่พบข้อมูล</td></tr>'}</tbody></table></div></section>`;document.body.appendChild(ov);$('#remainClose').onclick=()=>ov.remove();$('#remainCsv').onclick=()=>csv(data);ov.onclick=e=>{if(e.target===ov)ov.remove()}}
function install(){const a=document.querySelector('.actions');if(a&&!$('#remainSummaryBtn')){const b=document.createElement('button');b.id='remainSummaryBtn';b.type='button';b.className='outline';b.textContent='สรุปของเหลือ/ขาด';b.onclick=openSummary;a.prepend(b)}}
function wrap(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.__remain276)return false;const old=window.DOIT_JSON_APP.load.bind(window.DOIT_JSON_APP);window.DOIT_JSON_APP.load=(payload,m={})=>{payloadRef=payload;meta=m||{};rows=(payload.rows||payload||[]).map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store),tele:T(r.tele),isTele:!!r.isTele,ps:T(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));old(payload,m);setTimeout(install,120)};window.DOIT_JSON_APP.__remain276=true;return true}
function boot(){install();if(!wrap())setTimeout(boot,300)}document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();})();